import time
from ag2.callbacks import CallbackHandler

class LatencyMonitor(CallbackHandler):
    def __init__(self):
        self.start_time = None

    def on_message_start(self, message):
        self.start_time = time.time()

    def on_message_end(self, message):
        if self.start_time:
            latency = time.time() - self.start_time
            if latency > 0.5:  # 500ms budget
                raise TimeoutError(f'Latency exceeded: {latency}s')

# Register in groupchat
monitor = LatencyMonitor()
groupchat.register_callback(monitor)

