from vex import Vex
from ag2.callbacks import CallbackHandler

# Initialize Vex for high-risk voice agents
vex = Vex(api_key='your-vex-key')

class VexHook(CallbackHandler):
    def on_message_create(self, message):
        # Verify before TTS
        result = vex.verify(
            messages=[{'role': 'user', 'content': message.content}],
            checks={
                'appropriateness': 'strict',
                'latency': 500,
                'coherence': 'conversation',
                'safety': 'block'
            }
        )
        if not result.passed:
            return {'content': '[Blocked by Vex safety filter]', 'block': True}
        return message

# Register globally
vex_hook = VexHook()
groupchat.register_callback(vex_hook)

class CoherenceVexHook(VexHook):
    def __init__(self):
        super().__init__()
        self.conversation_history = []

    def on_message_create(self, message):
        self.conversation_history.append(message)

        # Limit history for latency
        if len(self.conversation_history) > 10:
            self.conversation_history = self.conversation_history[-5:]

        result = vex.verify(
            messages=self.conversation_history,
            checks={'coherence': {'topic_drift': 'low'}}
        )

        if result.score < 0.8:
            return {'content': 'Staying on topic...', 'redirect': True}
        return message

class VoiceSafetyPipeline(VexHook):
    async def verify_pipeline(self, message, start_time):
        # Parallel safety + latency check
        latency = time.time() - start_time

        result = await vex.verify_async(
            messages=[message],
            checks={
                'safety': {'categories': ['hate', 'violence', 'illegal']},
                'latency': {'budget': 400 - latency*1000}  # Remaining ms
            },
            timeout=100  # 100ms max
        )

        if not result.passed or latency > 0.45:
            return {'content': '[Response filtered: safety/latency]', 'safe': False}
        return message

